<?php
namespace App\Http\Controllers\Inventory; use App\Http\Controllers\Controller; use App\Models\Inventory\{InventoryCategory,InventoryCondition,InventoryItem,InventoryLocation,InventoryMeasurementUnit}; use Illuminate\Http\Request; use Illuminate\Support\Str; use Illuminate\Validation\Rule;
class InventoryCrudController extends Controller{
 public function categories(Request $r){$q=InventoryCategory::withCount('items')->when($r->q,fn($x)=>$x->where('name','like','%'.$r->q.'%')->orWhere('code','like','%'.$r->q.'%'))->paginate(15); return view('inventory.categories.index',['categories'=>$q]);} public function storeCategory(Request $r){InventoryCategory::create($r->validate(['code'=>'required|alpha_dash|max:40|unique:inventory_categories,code','name'=>'required|max:255','description'=>'nullable|string','is_active'=>'boolean'])+['created_by'=>$r->user()->id]); return back()->with('status','Kategori inventaris disimpan.');} public function updateCategory(Request $r, InventoryCategory $category){$category->update($r->validate(['code'=>['required','alpha_dash','max:40',Rule::unique('inventory_categories','code')->ignore($category)],'name'=>'required|max:255','description'=>'nullable|string','is_active'=>'boolean'])+['updated_by'=>$r->user()->id]); return back()->with('status','Kategori inventaris diperbarui.');}
 public function locations(Request $r){return view('inventory.locations.index',['locations'=>InventoryLocation::withCount('balances')->when($r->type,fn($q)=>$q->where('type',$r->type))->when($r->q,fn($q)=>$q->where('name','like','%'.$r->q.'%')->orWhere('code','like','%'.$r->q.'%'))->paginate(15)]);} public function storeLocation(Request $r){InventoryLocation::create($r->validate(['code'=>'required|alpha_dash|max:40|unique:inventory_locations,code','name'=>'required|max:255','type'=>'required|max:80','building'=>'nullable|max:100','floor'=>'nullable|max:50','person_in_charge'=>'nullable|max:120','description'=>'nullable','is_active'=>'boolean'])); return back()->with('status','Lokasi inventaris disimpan.');} public function updateLocation(Request $r, InventoryLocation $location){$location->update($r->validate(['code'=>['required','alpha_dash','max:40',Rule::unique('inventory_locations','code')->ignore($location)],'name'=>'required|max:255','type'=>'required|max:80','building'=>'nullable|max:100','floor'=>'nullable|max:50','person_in_charge'=>'nullable|max:120','description'=>'nullable','is_active'=>'boolean'])); return back()->with('status','Lokasi inventaris diperbarui.');}
 public function conditions(){return view('inventory.conditions.index',['conditions'=>InventoryCondition::orderBy('display_order')->paginate(20)]);} public function updateCondition(Request $r, InventoryCondition $condition){$condition->update($r->validate(['name'=>'required|max:120','severity'=>'required|max:40','display_order'=>'integer|min:0','is_active'=>'boolean'])); return back()->with('status','Kondisi barang diperbarui.');}
 public function items(Request $r){$items=InventoryItem::with('category','unit','primaryLocation')->withSum('balances','quantity')->when($r->q,fn($q)=>$q->where('name','like','%'.$r->q.'%')->orWhere('code','like','%'.$r->q.'%'))->when($r->category_id,fn($q)=>$q->where('inventory_category_id',$r->category_id))->paginate(15); return view('inventory.items.index',['items'=>$items,'categories'=>InventoryCategory::get(),'locations'=>InventoryLocation::get(),'conditions'=>InventoryCondition::get()]);} public function createItem(){return view('inventory.items.form',$this->refs()+['item'=>new InventoryItem]);} public function storeItem(Request $r){$d=$this->itemData($r); $d['created_by']=$r->user()->id; $item=InventoryItem::create($d); return redirect()->route('inventory.items.show',$item)->with('status','Barang inventaris disimpan.');} public function showItem(InventoryItem $item){return view('inventory.items.show',['item'=>$item->load('category','unit','primaryLocation','balances.location','balances.condition','transactions.fromLocation','transactions.toLocation','transactions.fromCondition','transactions.toCondition','itemUnits.location','itemUnits.condition')]);} public function editItem(InventoryItem $item){return view('inventory.items.form',$this->refs()+['item'=>$item]);} public function updateItem(Request $r, InventoryItem $item){$item->update($this->itemData($r,$item)+['updated_by'=>$r->user()->id]); return redirect()->route('inventory.items.show',$item)->with('status','Barang inventaris diperbarui.');}
 private function refs():array{return ['categories'=>InventoryCategory::where('is_active',1)->get(),'units'=>InventoryMeasurementUnit::where('is_active',1)->get(),'locations'=>InventoryLocation::where('is_active',1)->get()];} private function itemData(Request $r,?InventoryItem $item=null):array{return $r->validate(['code'=>['required','max:60',Rule::unique('inventory_items','code')->ignore($item)],'name'=>'required|max:255','inventory_category_id'=>'required|exists:inventory_categories,id','inventory_measurement_unit_id'=>'required|exists:inventory_measurement_units,id','primary_location_id'=>'nullable|exists:inventory_locations,id','tracking_type'=>'required|in:quantity,individual','brand'=>'nullable|max:120','model'=>'nullable|max:120','description'=>'nullable','acquisition_year'=>'nullable|integer|min:1900|max:2100','acquisition_date'=>'nullable|date','acquisition_source'=>'nullable|max:120','funding_source'=>'nullable|max:120','acquisition_value'=>'nullable|numeric|min:0','notes'=>'nullable','is_active'=>'boolean']);}}
